import{_ as t,c as n,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Erweiterte Funktionen: Multi-Agent & Skill-Entwicklung | OpenSkills","description":"Lernen Sie die erweiterten Funktionen von OpenSkills kennen, einschließlich Multi-Agent-Umgebungskonfiguration, benutzerdefinierte Skill-Entwicklung, CI/CD-Integration und Sicherheitsmechanismen zur effizienten Verwaltung komplexer Szenarien.","frontmatter":{"title":"Erweiterte Funktionen: Multi-Agent & Skill-Entwicklung | OpenSkills","sidebarTitle":"Multi-Agent & Benutzerdefinierte Skills","subtitle":"Erweiterte Funktionen: Multi-Agent & Skill-Entwicklung","description":"Lernen Sie die erweiterten Funktionen von OpenSkills kennen, einschließlich Multi-Agent-Umgebungskonfiguration, benutzerdefinierte Skill-Entwicklung, CI/CD-Integration und Sicherheitsmechanismen zur effizienten Verwaltung komplexer Szenarien.","order":3},"headers":[],"relativePath":"de/numman-ali/openskills/advanced/index.md","filePath":"de/numman-ali/openskills/advanced/index.md"}'),r={name:"de/numman-ali/openskills/advanced/index.md"};function l(s,e,u,d,h,o){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="erweiterte-funktionen" tabindex="-1">Erweiterte Funktionen <a class="header-anchor" href="#erweiterte-funktionen" aria-label="Permalink to &quot;Erweiterte Funktionen&quot;">​</a></h1><p>Dieser Abschnitt behandelt die fortgeschrittene Verwendung von OpenSkills, einschließlich Multi-Agent-Umgebungskonfiguration, benutzerdefinierte Ausgaben, Symlink-Entwicklung, Skill-Erstellung, CI/CD-Integration und Sicherheitsmechanismen. Nach der Beherrschung dieser Inhalte können Sie Skills effizient in komplexen Szenarien verwalten und Ihre eigene exklusive Skill-Bibliothek erstellen.</p><div class="warning custom-block"><p class="custom-block-title">Voraussetzungen</p><p>Stellen Sie vor dem Lernen dieses Kapitels sicher, dass Sie Folgendes abgeschlossen haben:</p><ul><li><a href="./../start/quick-start/">Schnellstart</a>: Grundlagen der Installation und Verwendung</li><li><a href="./../start/first-skill/">Erste Skill-Installation</a>: Skill-Installationsmethoden beherrschen</li><li><a href="./../start/sync-to-agents/">Skills zu AGENTS.md synchronisieren</a>: Skill-Synchronisationsmechanismus verstehen</li></ul></div><h2 id="inhalt-dieses-kapitels" tabindex="-1">Inhalt dieses Kapitels <a class="header-anchor" href="#inhalt-dieses-kapitels" aria-label="Permalink to &quot;Inhalt dieses Kapitels&quot;">​</a></h2><h3 id="multi-agent-ausgabekonfiguration" tabindex="-1">Multi-Agent &amp; Ausgabekonfiguration <a class="header-anchor" href="#multi-agent-ausgabekonfiguration" aria-label="Permalink to &quot;Multi-Agent &amp; Ausgabekonfiguration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tutorial</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./universal-mode/">Universal-Modus</a></td><td>Konfiguration der Multi-Agent-Umgebung, die Claude Code, Cursor, Windsurf und andere gleichzeitig unterstützt, mit automatischer Erkennung der aktuellen Agent-Umgebung</td></tr><tr><td><a href="./custom-output-path/">Benutzerdefinierter Ausgabepfad</a></td><td>Konfigurieren von AGENTS.md-Ausgabepfaden, Unterstützung für projektspezifische oder global einheitliche Konfiguration, automatische Anpassung an unterschiedliche Arbeitsabläufe</td></tr></tbody></table><h3 id="skill-entwicklung" tabindex="-1">Skill-Entwicklung <a class="header-anchor" href="#skill-entwicklung" aria-label="Permalink to &quot;Skill-Entwicklung&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tutorial</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./symlink-support/">Symlink-Unterstützung</a></td><td>Symlink-basierte Entwicklung für git-basierte Skill-Updates und lokale Entwicklungsworkflows, Skill-Sharing über mehrere Projekte</td></tr><tr><td><a href="./create-skills/">Benutzerdefinierte Skills erstellen</a></td><td>Erstellen von SKILL.md-Skill-Dateien von Grund auf, Beherrschung von YAML-Frontmatter und Verzeichnisstrukturstandards</td></tr><tr><td><a href="./skill-structure/">Skill-Struktur im Detail</a></td><td>Tiefes Verständnis der vollständigen SKILL.md-Feldspezifikation, Ressourcendesign für references/scripts/assets/ und Leistungsoptimierung</td></tr></tbody></table><h3 id="automatisierung-sicherheit" tabindex="-1">Automatisierung &amp; Sicherheit <a class="header-anchor" href="#automatisierung-sicherheit" aria-label="Permalink to &quot;Automatisierung &amp; Sicherheit&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tutorial</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./ci-integration/">CI/CD-Integration</a></td><td>Automatische Generierung von AGENTS.md in CI/CD-Pipelines, Unterstützung für GitHub Actions, GitLab CI und andere Tools, nahtlose Integration in bestehende Arbeitsabläufe</td></tr><tr><td><a href="./security/">Sicherheitsübersicht</a></td><td>Verständnis der dreistufigen Schutzmechanismen: Pfad-Traversalschutz, sichere Symlink-Verarbeitung, YAML-Parsing-Sicherheit und weitere Sicherheitsmaßnahmen</td></tr></tbody></table><h3 id="umfassende-leitfaden" tabindex="-1">Umfassende Leitfäden <a class="header-anchor" href="#umfassende-leitfaden" aria-label="Permalink to &quot;Umfassende Leitfäden&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tutorial</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./best-practices/">Best Practices</a></td><td>Zusammenfassung von Erfahrungen in Projektkonfiguration, Skill-Verwaltung und Teamzusammenarbeit, um Ihnen zu helfen, OpenSkills effizient zu nutzen</td></tr></tbody></table><h2 id="lernpfad-empfehlungen" tabindex="-1">Lernpfad-Empfehlungen <a class="header-anchor" href="#lernpfad-empfehlungen" aria-label="Permalink to &quot;Lernpfad-Empfehlungen&quot;">​</a></h2><p>Wählen Sie je nach Anwendungsszenario den passenden Lernpfad:</p><h3 id="pfad-a-multi-agent-benutzer" tabindex="-1">Pfad A: Multi-Agent-Benutzer <a class="header-anchor" href="#pfad-a-multi-agent-benutzer" aria-label="Permalink to &quot;Pfad A: Multi-Agent-Benutzer&quot;">​</a></h3><p>Wenn Sie gleichzeitig mehrere KI-Codierungstools verwenden (Claude Code + Cursor + Windsurf usw.):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Universal-Modus → Benutzerdefinierter Ausgabepfad → Best Practices</span></span></code></pre></div><h3 id="pfad-b-skill-entwickler" tabindex="-1">Pfad B: Skill-Entwickler <a class="header-anchor" href="#pfad-b-skill-entwickler" aria-label="Permalink to &quot;Pfad B: Skill-Entwickler&quot;">​</a></h3><p>Wenn Sie Ihre eigenen Skills erstellen und mit dem Team teilen möchten:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzerdefinierte Skills erstellen → Skill-Struktur im Detail → Symlink-Unterstützung → Best Practices</span></span></code></pre></div><h3 id="pfad-c-devops-automatisierung" tabindex="-1">Pfad C: DevOps/Automatisierung <a class="header-anchor" href="#pfad-c-devops-automatisierung" aria-label="Permalink to &quot;Pfad C: DevOps/Automatisierung&quot;">​</a></h3><p>Wenn Sie OpenSkills in CI/CD-Workflows integrieren müssen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CI/CD-Integration → Sicherheitsübersicht → Best Practices</span></span></code></pre></div><h3 id="pfad-d-vollstandiges-lernen" tabindex="-1">Pfad D: Vollständiges Lernen <a class="header-anchor" href="#pfad-d-vollstandiges-lernen" aria-label="Permalink to &quot;Pfad D: Vollständiges Lernen&quot;">​</a></h3><p>Wenn Sie alle erweiterten Funktionen umfassend beherrschen möchten, lernen Sie in dieser Reihenfolge:</p><ol><li><a href="./universal-mode/">Universal-Modus</a> - Multi-Agent-Umgebungsgrundlagen</li><li><a href="./custom-output-path/">Benutzerdefinierter Ausgabepfad</a> - Flexible Ausgabekonfiguration</li><li><a href="./symlink-support/">Symlink-Unterstützung</a> - Effizienter Entwicklungsworkflow</li><li><a href="./create-skills/">Benutzerdefinierte Skills erstellen</a> - Einstieg in die Skill-Erstellung</li><li><a href="./skill-structure/">Skill-Struktur im Detail</a> - Tiefes Verständnis des Skill-Formats</li><li><a href="./ci-integration/">CI/CD-Integration</a> - Automatisierte Bereitstellung</li><li><a href="./security/">Sicherheitsübersicht</a> - Detaillierte Sicherheitsmechanismen</li><li><a href="./best-practices/">Best Practices</a> - Erfahrungszusammenfassung</li></ol><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie:</p><ul><li>Die <a href="./../faq/faq/">FAQ</a> konsultieren, um auftretende Probleme zu lösen</li><li>Die <a href="./../appendix/cli-api/">CLI API-Referenz</a> lesen, um die vollständige Befehlszeilenschnittstelle zu verstehen</li><li>Das <a href="./../appendix/agents-md-format/">AGENTS.md-Format</a> lesen, um das generierte Dateiformat tief zu verstehen</li><li>Das <a href="./../changelog/changelog/">Changelog</a> ansehen, um die neuesten Funktionen und Änderungen zu erfahren</li></ul>',29)])])}const f=t(r,[["render",l]]);export{g as __pageData,f as default};
